const argv = ['node', 'mdtldr', 'search', 'memory', '-n', '2', 'docs/'];
const isFlag = (arg) => arg.startsWith('-');
const flagsWithValues = new Set(['-n', '--limit', '-t', '--tokens', '--threshold', '-r', '--root']);
const flagTakesValue = (flag) => {
  if (flag.includes('=')) return false;
  return flagsWithValues.has(flag);
};
const preprocessArgv = (argv) => {
  const nodeAndScript = argv.slice(0, 2);
  const userArgs = argv.slice(2);
  if (userArgs.length === 0) return argv;
  const firstArg = userArgs[0];
  if (!firstArg || isFlag(firstArg)) return argv;
  const subcommand = firstArg;
  const restArgs = userArgs.slice(1);
  const flags = [];
  const positionals = [];
  let i = 0;
  while (i < restArgs.length) {
    const arg = restArgs[i];
    if (!arg) { i++; continue; }
    if (isFlag(arg)) {
      if (arg.includes('=')) {
        flags.push(arg);
        i++;
      } else if (flagTakesValue(arg)) {
        flags.push(arg);
        i++;
        if (i < restArgs.length) {
          const nextArg = restArgs[i];
          if (nextArg && !isFlag(nextArg)) {
            flags.push(nextArg);
            i++;
          }
        }
      } else {
        flags.push(arg);
        i++;
      }
    } else {
      positionals.push(arg);
      i++;
    }
  }
  return [...nodeAndScript, subcommand, ...flags, ...positionals];
};
console.log('Input:', argv);
console.log('Output:', preprocessArgv(argv));
"

