            yield* Console.log(`  Tokens used: ${embedResult.tokensUsed}`)
            yield* Console.log(`  Cost: $${embedResult.cost.toFixed(6)}`)
            yield* Console.log(`  Duration: ${embedResult.duration}ms`)
          }
        }

        if (json) {
          yield* Console.log(formatJson(result, pretty))
        }
      }
    }),
